{
  "user_query": "How did tech compare to energy 2017-2021?",
  "intent": "sector_comparison",
  "tickers_or_sectors": "sector:Information Technology,sector:Energy",
  "time_window": {
    "start": "2017-01",
    "end": "2021-12",
    "note": "User-specified full-coverage window; matches available data (Jan 2017–Dec 2021)."
  },
  "quantitative_questions": [
    "Compute equal-weighted sector monthly return series for Information Technology and Energy from 2017-01 to 2021-12 and report the cumulative total return for each sector over the full period.",
    "Calculate annualized return and annualized volatility for each sector over 2017-01 to 2021-12 (use monthly returns; annualize mean*12 and std*sqrt(12)).",
    "Compute maximum drawdown and the drawdown time series for each sector over the period, and report the date and magnitude of each sector's worst drawdown.",
    "Compute rolling 12-month cumulative returns for each sector and identify subperiods (months) when Information Technology outperformed Energy and vice versa.",
    "Calculate the monthly return correlation between the two sector return series and report summary statistics (mean, median of monthly differences)."
  ],
  "qualitative_questions": [
    "What macro, industry, and demand/supply factors explain the relative performance of Information Technology vs Energy during 2017–2021 (e.g., secular tech growth, oil price cycles) — requires external sources.",
    "Which major events or policy/regulatory developments during 2017–2021 drove the largest divergences between tech and energy (e.g., oil price shocks, COVID-19 demand shock) — requires external news and research sources."
  ],
  "chart_requests": [
    {
      "chart_id": "sector_cumulative_returns",
      "chart_type": "line",
      "description": "Plot cumulative growth of $1 invested in equal-weighted Information Technology and Energy sector portfolios from 2017-01 to 2021-12 on a single line chart (x-axis = month, y-axis = cumulative value). Include legend and monthly gridlines."
    },
    {
      "chart_id": "sector_annualized_return_volatility",
      "chart_type": "bar",
      "description": "Grouped bar chart with two groups (Information Technology, Energy). For each sector show two bars: annualized return and annualized volatility. Add numeric labels above bars and order sectors left-to-right: Information Technology, Energy."
    },
    {
      "chart_id": "sector_rolling_12m_returns",
      "chart_type": "line",
      "description": "Plot 12-month rolling cumulative returns for both sectors on the same chart (x-axis = month end, y-axis = 12-month cumulative return). Highlight and annotate months where the sign of the performance gap changes (crossovers)."
    },
    {
      "chart_id": "sector_drawdown_series",
      "chart_type": "line",
      "description": "Plot drawdown time series for each sector (percentage drawdown from prior peak) from 2017-01 to 2021-12 on a single chart. Also produce a small table or inset listing each sector's maximum drawdown and the date it occurred."
    }
  ],
  "presentation_angle": "Show a concise side-by-side performance and risk comparison: total and rolling returns, volatility, and drawdowns for Information Technology vs Energy from 2017–2021, and point to timing of major divergences to motivate qualitative explanations.",
  "out_of_scope_notes": "Analysis limited to Jan 2017–Dec 2021 (the available CSVs). Any causal explanations, news events, policy impacts, or fundamentals required to explain why one sector outperformed the other are out of scope for the CSVs and require external sources."
}
